const fs = require('fs');

const createBundleMap = (stats) =>
  Object.keys(stats.nodeMetas)
    .filter((uid) => stats.nodeMetas[uid].id.endsWith('.html'))
    .reduce(
      (acc, uid) => ({
        ...acc,
        // Turn "/index.html" > "index"
        [stats.nodeMetas[uid].id.substring(1).split('.')[0]]: { ...stats.nodeMetas[uid], uid },
      }),
      {}
    );

const parseStats = (file) => {
  const stats = JSON.parse(fs.readFileSync(file));
  return {
    ...stats,
    bundleMap: createBundleMap(stats),
  };
};

const generateImportForBundle = (stats, startUid) => {
  const imports = new Set();

  // Recursively create set of UIDs included in a bundle
  const getImports = (uid) => {
    if (!imports.has(uid)) {
      imports.add(uid);
      stats.nodeMetas[uid].imported.forEach((i) => getImports(i.uid));
    }
  };
  getImports(startUid);

  return imports;
};

const generateImports = (stats) => {
  // consider modules that are imported by a top level html file
  const importMap = Object.keys(stats.bundleMap).reduce((map, bundleName) => {
    map[bundleName] = generateImportForBundle(
      stats,
      stats.bundleMap[bundleName].uid,
      map[bundleName]
    );
    return map;
  }, {});

  // consider all other modules, perhaps dynamically imported or just dead code
  const otherSet = new Set();
  Object.keys(stats.nodeMetas)
    .filter((uid) => !Object.values(importMap).some((i) => i.has(uid)))
    .forEach((uid) => otherSet.add(uid));
  importMap.other = otherSet;

  return importMap;
};

const getSizes = (stats) => {
  const sizeMap = Object.values(stats.nodeParts).reduce((acc, part) => {
    acc[part.metaUid] = part.renderedLength;
    return acc;
  }, {});

  const importMap = generateImports(stats);
  const sizes = Object.keys(importMap).map((id) => {
    const imports = importMap[id];

    const totalSize = Array.from(imports).reduce((sum, uid) => sum + (sizeMap[uid] || 0), 0);
    const biggestModules = Array.from(imports)
      .map((uid) => ({ size: sizeMap[uid], uid }))
      .sort((a, b) => b.size - a.size)
      .slice(0, 5)
      .map(({ size, uid }) => ({ id: stats.nodeMetas[uid].id, size }));

    return { biggestModules, id, moduleCount: imports.size, totalSize };
  });

  return sizes;
};

const getDiff = (stats, importMap, a, b) => {
  if (!a || !b) {
    console.error(`'diff' mode requires 2 arguments`);
    process.exit(1);
  }

  return Array.from(importMap[a])
    .filter((uid) => !importMap[b].has(uid))
    .map((uid) => stats.nodeMetas[uid].id);
};

const printDiffs = (stats, a, b) => {
  const importMap = generateImports(stats);

  console.log(`In ${a} but not ${b}`);
  getDiff(stats, importMap, a, b).forEach((id) => {
    console.log(id);
  });
  console.log(`\nIn ${b} but not ${a}`);
  getDiff(stats, importMap, b, a).forEach((id) => {
    console.log(id);
  });
};

